```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer, hexi::init_empty);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    NetworkPacket packet;

    // Read packet_id with endian conversion
    stream >> hexi::endian::le(packet.packet_id);

    // Read username using prefixed adaptor
    stream >> packet.username;

    // Read scores vector using prefixed adaptor
    stream >> hexi::prefixed(packet.scores);

    // Read metadata as null-terminated string
    stream >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    stream.skip(buffer.size() - stream.total_read());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer, hexi::init_empty);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    PacketInfo info;

    // Use span() to get zero-copy view of packet_id
    auto id_span = stream.span(1); // Returns span of 1 element (uint32_t)
    info.packet_id = id_span[0];

    // Read username using prefixed adaptor to get string_view
    std::string_view username;
    stream >> hexi::prefixed(username);
    info.username = username;

    // Skip scores vector by reading count and skipping data
    uint32_t scores_count;
    stream >> hexi::endian::le(scores_count);
    stream.skip(scores_count * sizeof(uint32_t));

    return info;
}
```

## Key Implementation Points:

### `deserialize_packet` function:
1. **Buffer Adaptor Creation**: Uses `buffer_adaptor` to wrap the input span and `init_empty_t` to initialize it
2. **Binary Stream Creation**: Creates a `binary_stream` from the buffer adaptor
3. **Packet ID Reading**: Uses `endian::le` adaptor for little-endian conversion
4. **Username Reading**: Uses default prefixed string deserialization
5. **Scores Vector**: Uses `prefixed` adaptor to read count and container
6. **Metadata**: Uses `null_terminated` adaptor for zero-copy string view
7. **Padding Skip**: Calculates remaining bytes and skips them using `skip()`

### `extract_packet_info` function:
1. **Zero-Copy View**: Uses `span(1)` to get a view of the first 4 bytes (packet_id)
2. **String View Extraction**: Uses `prefixed` adaptor to get a string_view without copying
3. **Scores Skipping**: Reads the count and skips the entire vector data using `skip()`
4. **Efficient Processing**: Extracts only needed information without full deserialization

