struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    Header header;

    // Get read pointer before peeking
    auto* initial_ptr = read_adaptor.read_ptr();

    // Peek at header using copy() - copy each field separately (doesn't advance read cursor)
    // Use read_ptr() to manually access data at different offsets
    const uint8_t* data_ptr = reinterpret_cast<const uint8_t*>(read_adaptor.read_ptr());
    std::memcpy(&header.magic, data_ptr, sizeof(header.magic));
    std::memcpy(&header.version, data_ptr + sizeof(header.magic), sizeof(header.version));

    // Verify read pointer hasn't changed
    auto* after_peek_ptr = read_adaptor.read_ptr();

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    std::vector<uint8_t> result;

    // Peek at first byte
    uint8_t first_byte = 0;
    read_adaptor.copy(&first_byte, 1);

    // If first byte is non-zero, read the data
    if (first_byte != 0) {
        std::size_t data_size = read_adaptor.size();
        result.resize(data_size);
        read_adaptor.read(result.data(), data_size);
    }

    return result;
}

